from src.nodes.base import BaseNode

async def execute(self, inputs):
    name = inputs.get('dict_name') or self.get_parameter('dict_name', '')
    provided = inputs.get('dict')
    if provided is None or provided == {}:
        d = BaseNode.memory.get(name) if name else {}
    else:
        d = dict(provided)

    key = inputs.get('key')
    val = inputs.get('value')
    if key is None:
        self.log_info('No key provided')
        await self.set_output('result_dict', d)
        await self.set_output('success', False)
        await self.set_output('exec_out', True)
        return {'result_dict': d, 'success': False}

    try:
        d[key] = val
        success = True
        if name:
            BaseNode.memory[name] = d
    except Exception as e:
        self.log_info(f'Error setting dict value: {e}')
        success = False

    await self.set_output('result_dict', d)
    await self.set_output('success', success)
    await self.set_output('exec_out', True)
    return {'result_dict': d, 'success': success}
